import{_ as t,o as i,c as a,a2 as l}from"./chunks/framework.Bix3-HpO.js";const c=JSON.parse('{"title":"Theme Strings","description":"FXT Theme Strings","frontmatter":{"title":"Theme Strings","description":"FXT Theme Strings","weight":100,"extra":{"order":100},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/fxt/theme-strings"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/fxt/theme-strings"}],["meta",{"property":"og:title","content":"Theme Strings"}],["meta",{"property":"og:description","content":"FXT Theme Strings"}],["meta",{"name":"twitter:title","content":"Theme Strings"}],["meta",{"name":"twitter:description","content":"FXT Theme Strings"}]]},"headers":[],"relativePath":"docs/fxt/theme-strings.md","filePath":"docs/fxt/theme-strings.md"}'),n={name:"docs/fxt/theme-strings.md"};function r(s,e,o,g,h,d){return i(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="theme-strings" tabindex="-1">Theme Strings <a class="header-anchor" href="#theme-strings" aria-label="Permalink to &quot;Theme Strings&quot;">​</a></h1><p>FXT theme allows you to customize various text strings throughout your website through the WordPress Customizer.</p><hr><h2 id="accessing-theme-strings" tabindex="-1">Accessing Theme Strings <a class="header-anchor" href="#accessing-theme-strings" aria-label="Permalink to &quot;Accessing Theme Strings&quot;">​</a></h2><p>To customize theme strings:</p><ol><li>In WordPress dashboard, click on <strong>FXT Options</strong> in the left sidebar</li><li>Click on <strong>💬 Strings</strong> in the submenu</li><li>You&#39;ll be taken to the FXT Theme Strings page</li></ol><hr><h2 id="available-string-categories" tabindex="-1">Available String Categories <a class="header-anchor" href="#available-string-categories" aria-label="Permalink to &quot;Available String Categories&quot;">​</a></h2><h3 id="button-strings" tabindex="-1">Button Strings <a class="header-anchor" href="#button-strings" aria-label="Permalink to &quot;Button Strings&quot;">​</a></h3><p>Customize button text and labels throughout the theme.</p><p><strong>Available Strings</strong>:</p><ul><li>Real Account Button</li><li>Real Account Button (Short)</li><li>Demo Account Button</li><li>Demo Account Button (Short)</li><li>More Details Button</li></ul><h3 id="rating-strings" tabindex="-1">Rating Strings <a class="header-anchor" href="#rating-strings" aria-label="Permalink to &quot;Rating Strings&quot;">​</a></h3><p>Customize rating-related text and labels.</p><p><strong>Available Strings</strong>:</p><ul><li>Rating Label</li><li>Overall Rating Label</li><li>Trading Instruments Rating Label</li><li>Platforms and Tools Rating Label</li><li>Fees Rating Label</li><li>Security and Fairness Rating Label</li><li>Deposit and Withdrawal Rating Label</li><li>Customer Service Rating Label</li><li>More Ratings Button</li></ul><h3 id="trading-terms" tabindex="-1">Trading Terms <a class="header-anchor" href="#trading-terms" aria-label="Permalink to &quot;Trading Terms&quot;">​</a></h3><p>Customize trading-related terminology and labels.</p><p><strong>Available Strings</strong>:</p><ul><li>Trading Options Label</li><li>Account Information Label</li><li>Trading Instruments Label</li><li>Trading Conditions Label</li><li>Trading Tools Label</li><li>Mobile Trading Label</li><li>Min Trade Size Label</li><li>Average Spread Label</li><li>Max Leverage Label</li><li>Min Deposit Label</li></ul><h3 id="trading-instruments" tabindex="-1">Trading Instruments <a class="header-anchor" href="#trading-instruments" aria-label="Permalink to &quot;Trading Instruments&quot;">​</a></h3><p>Customize trading instrument labels.</p><p><strong>Available Strings</strong>:</p><ul><li>Currency Pairs Label</li><li>Cryptocurrencies Label</li><li>Precious Metals Label</li><li>Commodities Label</li><li>Stocks Label</li><li>Indices Label</li></ul><h3 id="form-strings" tabindex="-1">Form Strings <a class="header-anchor" href="#form-strings" aria-label="Permalink to &quot;Form Strings&quot;">​</a></h3><p>Customize form labels and messages.</p><p><strong>Available Strings</strong>:</p><ul><li>Name Field Label</li><li>Email Field Label</li><li>Message Field Label</li><li>Required Field Text</li><li>Success Message Text</li><li>Error Message Text</li></ul><h3 id="review-and-content" tabindex="-1">Review and Content <a class="header-anchor" href="#review-and-content" aria-label="Permalink to &quot;Review and Content&quot;">​</a></h3><p>Customize review and content-related text.</p><p><strong>Available Strings</strong>:</p><ul><li>Review Link</li><li>Review Link (Short)</li><li>Review Link with Broker Name</li><li>Review Links Label</li><li>Author By Label</li><li>Author On Label</li><li>Author Posts Label</li></ul><hr><h2 id="customizing-strings" tabindex="-1">Customizing Strings <a class="header-anchor" href="#customizing-strings" aria-label="Permalink to &quot;Customizing Strings&quot;">​</a></h2><h3 id="making-changes" tabindex="-1">Making Changes <a class="header-anchor" href="#making-changes" aria-label="Permalink to &quot;Making Changes&quot;">​</a></h3><ol><li>In the FXT Theme Strings page, click <strong>Add Custom String</strong></li><li>Select the string you want to customize from the dropdown</li><li>Enter your custom value in the text field</li><li>Click <strong>Update</strong> to save changes</li></ol><h3 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h3><ul><li>Keep text concise and clear</li><li>Maintain consistent terminology</li><li>Test changes on different pages</li><li>Consider mobile display length</li></ul><hr><h2 id="string-management" tabindex="-1">String Management <a class="header-anchor" href="#string-management" aria-label="Permalink to &quot;String Management&quot;">​</a></h2><h3 id="default-values" tabindex="-1">Default Values <a class="header-anchor" href="#default-values" aria-label="Permalink to &quot;Default Values&quot;">​</a></h3><p>All strings have default values that are used if no custom text is provided.</p><h3 id="string-management-1" tabindex="-1">String Management <a class="header-anchor" href="#string-management-1" aria-label="Permalink to &quot;String Management&quot;">​</a></h3><ul><li>Only add strings that you want to override with custom values</li><li>Strings not customized will use their default values</li><li>You can remove customizations to revert to default values</li><li>The system validates for duplicate string selections</li></ul><hr><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><p><a href="/docs/fxt/theme-customizer">Theme Customizer</a></p>',47)])])}const m=t(n,[["render",r]]);export{c as __pageData,m as default};
